  const out = {};
  for (const t of tables) {
    try {
      const cols = await db.query("'`SELECT column_name, data_type, is_nullable FROM information_schema.columns WHERE table_schema = current_schema() AND table_name = $1 ORDER BY ordinal_position`, [t]);
