    case "Support":
      return "Support investigation for delayed high-value order";
    case "Finance":
      return `Finance review for ${tier} account billing and contract exposure`;
    case "Executive Sponsor":
      return `Executive recovery oversight for ${tier} account`;
    default:
      return `${ownerGroup} recovery task for ${title}`;
  }
}

function buildAuditDetail(request, account, contract, ownerRouting, riskSignals, timelineSummary) {
  const accountName = account?.name || request.account_id;
  const tier = account?.tier || "unknown";
  const supportPlan = contract?.support_plan || "unknown";
  const riskSummary = riskSignals.map((item) => item.signal_name).join(", ");

  return `Escalation opened for ${accountName} (${tier}, ${supportPlan} support). Owner routing: ${ownerRouting}. Risk signals: ${riskSummary}. Activity trail: ${timelineSummary || "none"}.`;
}

