    const facts = await readFactsFromDb(db);
    const accountId = facts.account.accountId;
    const requestId = `req-${accountId}`;
    const title = facts.account.name || accountId;
    const qualified = qualifies(facts, now);
    const signals = signalsOf(facts, now);
    const owners = qualified ? ownersOf(facts, now) : [];
    const status = qualified ? RULES.escalationStatus : RULES.monitorStatus;
    const riskSummary = `${signals.length} signals: ${signals.join(", ")}`;
    const nextStep = qualified ? `${owners[0]} recovery review by 16:00` : "Continue standard monitoring.";

